previewCss:
.darma-loader-darma-custom-531 {color: var(--loader-color, #2563eb);
  --loader-secondary-color: var(--loader-secondary-color, #38bdf8);
  --loader-bg: var(--loader-bg, #ffffff);
   display: inline-flex;
   gap: 10px;
}
.darma-loader-darma-custom-531:before, .darma-loader-darma-custom-531:after  {
  content: "";
   height: 20px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: linear-gradient(var(--loader-secondary-color, #38bdf8) 0 0) top/100% 40% no-repeat, radial-gradient(farthest-side,currentColor 95%,#0000) 50%/8px 8px no-repeat currentColor;
   animation: darma-loader-darma-custom-531-l7 1.5s infinite alternate ease-in;
}
@keyframes darma-loader-darma-custom-531-l7  {
  0%, 70% {background-size:100% 40%,8px 8px}
85% {background-size:100% 120%,8px 8px}
100% {background-size:100% 40%,8px 8px}
}

